const SEASON_FLAVOR = {
  Greenleaf: { arrival_text: "Greenleaf arrives with warm stones, buzzing bees, and prey-scent drifting through every fern tunnel.", midseason_text: "The sun rides high over the trees, and patrols return dusty, thirsty, and proud of heavy fresh-kill." },
  "Leaf-fall": { arrival_text: "Leaf-fall scatters gold and red across the territory, hiding pawprints beneath crisp leaves.", midseason_text: "Cold winds tug at the dens, and every warrior knows full bellies now will matter when snow comes." },
  "Leaf-bare": { arrival_text: "Leaf-bare grips the forest with frozen claws, thinning prey and turning every cough into a warning.", midseason_text: "Snow muffles the camp, herbs run low, and the Clan survives by sharing warmth, prey, and courage." },
  Newleaf: { arrival_text: "Newleaf pushes green shoots through old frost, and the first birdsong makes the nursery kits squeak with joy.", midseason_text: "Rain softens the earth, herbs rise fresh, and apprentices return from training with muddy paws and bright eyes." }
};

